import{_ as o,o as a,c as r,a0 as i}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"appendices/appendix-b-recommended-resources-readings.md","filePath":"appendices/appendix-b-recommended-resources-readings.md"}'),n={name:"appendices/appendix-b-recommended-resources-readings.md"};function t(s,e,c,l,d,u){return a(),r("div",null,[...e[0]||(e[0]=[i('<h2 id="appendix-b-recommended-resources-readings" tabindex="-1">Appendix B: Recommended Resources &amp; Readings <a class="header-anchor" href="#appendix-b-recommended-resources-readings" aria-label="Permalink to &quot;Appendix B: Recommended Resources &amp; Readings&quot;">​</a></h2><p>The following books, papers, conference presentations, and tools were referenced throughout the lectures:</p><h3 id="_1-books" tabindex="-1">1. Books <a class="header-anchor" href="#_1-books" aria-label="Permalink to &quot;1. Books&quot;">​</a></h3><ul><li><em>Software Engineering at Google</em> — Titus Winters, Tom Manshreck, and Hyrum Wright. (Introduces the concept of software engineering vs. programming).</li><li><em>The Go Programming Language</em> — Alan A. A. Donovan and Brian W. Kernighan. (Highly recommended textbook for deeper Go concepts).</li><li><em>Designing Data-Intensive Applications</em> — Martin Kleppmann. (Essential reference for database architecture and distributed systems).</li></ul><h3 id="_2-research-papers-articles" tabindex="-1">2. Research Papers &amp; Articles <a class="header-anchor" href="#_2-research-papers-articles" aria-label="Permalink to &quot;2. Research Papers &amp; Articles&quot;">​</a></h3><ul><li><em>&quot;Reflections on Trusting Trust&quot;</em> — Ken Thompson, 1984 ACM Turing Award Lecture. (Discusses compiler backdoors and dependency trust).</li><li><em>&quot;Our Software Dependency Problem&quot;</em> — Russ Cox, Go Team. (Analyzes the risks of third-party package ecosystems).</li><li><em>&quot;Communicating Sequential Processes (CSP)&quot;</em> — C. A. R. Hoare, 1978. (The theoretical basis for Go&#39;s channels and goroutines).</li><li><em>&quot;Reflections on Software Design&quot;</em> — Tony Hoare, 1980 ACM Turing Award Lecture. (Famous &quot;elegance in simplicity&quot; speech).</li></ul><h3 id="_3-conference-presentations-video-lectures" tabindex="-1">3. Conference Presentations &amp; Video Lectures <a class="header-anchor" href="#_3-conference-presentations-video-lectures" aria-label="Permalink to &quot;3. Conference Presentations &amp; Video Lectures&quot;">​</a></h3><ul><li><em>&quot;Simple Made Easy&quot;</em> — Rich Hickey, QCon 2011. (Distinguishes &quot;simple&quot; from &quot;easy&quot; and explains how to avoid architectural complexity).</li><li><em>&quot;Design, Composition, and Performance&quot;</em> — Rich Hickey, 2013.</li><li><em>&quot;Software That Fits in Your Head&quot;</em> — Dan North, GOTO 2016. (Advocates for microservices and component patterns that a developer can mentally represent).</li><li><em>&quot;Go Modules &amp; Secure Dependency Management&quot;</em> — Katie Hockman, GopherCon. (Deep-dive into the design of <code>go.sum</code>, the proxy server, and checksum databases).</li></ul><h3 id="_4-online-resources" tabindex="-1">4. Online Resources <a class="header-anchor" href="#_4-online-resources" aria-label="Permalink to &quot;4. Online Resources&quot;">​</a></h3><ul><li><code>github.com/mattforbiz/go-resources</code> — Lecture repository containing curated books, blogs, videos, and articles for learning Go.</li><li><code>golang.org/doc/effective_go</code> — Effective Go: the definitive guide to writing idiomatic Go code.</li><li><code>play.golang.org</code> — The standard Go Playground for compiling and sharing code snippets.</li><li><code>goplay.tools</code> — An enhanced web-based Go playground with autocomplete, syntax highlighting, and multi-file support.</li><li><a href="https://youtube.com/playlist?list=PLoILbKo9rG3skRCj37Kn5Zj803hhiuRK6&amp;si=a5vqHszTaa8T7HJ2" target="_blank" rel="noreferrer">Matt Holiday&#39;s Go Class Playlist</a> — Complete YouTube video lecture series with all 44 classes.</li></ul>',10)])])}const h=o(n,[["render",t]]);export{p as __pageData,h as default};
